import{_ as e,o as t,c as i,ag as n}from"./chunks/framework.BDReElpY.js";const p=JSON.parse('{"title":"SIR and Backends","description":"","frontmatter":{},"headers":[],"relativePath":"architecture/sir-and-backends.md","filePath":"architecture/sir-and-backends.md"}'),r={name:"architecture/sir-and-backends.md"};function s(o,a,l,d,c,h){return t(),i("div",null,[...a[0]||(a[0]=[n(`<h1 id="sir-and-backends" tabindex="-1">SIR and Backends <a class="header-anchor" href="#sir-and-backends" aria-label="Permalink to &quot;SIR and Backends&quot;">​</a></h1><p>SIR, short for Silicon IR, is the graph-oriented lowering path used for Vex&#39;s data-parallel execution model.</p><h2 id="what-sir-is-for" tabindex="-1">What SIR Is For <a class="header-anchor" href="#what-sir-is-for" aria-label="Permalink to &quot;What SIR Is For&quot;">​</a></h2><p>SIR is the part of the architecture that turns array-, tensor-, and graph-friendly computation into backend-specific execution plans.</p><p>Typical features routed through or associated with this layer include:</p><ul><li>tensor and mask lowering</li><li>fused arithmetic graphs</li><li>reductions and SIMD-oriented ops</li><li>backend-specific code generation</li></ul><h2 id="main-idea" tabindex="-1">Main Idea <a class="header-anchor" href="#main-idea" aria-label="Permalink to &quot;Main Idea&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Vex source</span></span>
<span class="line"><span>  -&gt; HIR</span></span>
<span class="line"><span>  -&gt; SIR graph</span></span>
<span class="line"><span>  -&gt; optimization / fusion / lowering</span></span>
<span class="line"><span>  -&gt; backend codegen</span></span></code></pre></div><h2 id="backend-maturity" tabindex="-1">Backend Maturity <a class="header-anchor" href="#backend-maturity" aria-label="Permalink to &quot;Backend Maturity&quot;">​</a></h2><p>The repository&#39;s own backend status documentation makes an important distinction: not every SIR backend is equally mature.</p><h3 id="generally-strongest-path" tabindex="-1">Generally strongest path <a class="header-anchor" href="#generally-strongest-path" aria-label="Permalink to &quot;Generally strongest path&quot;">​</a></h3><ul><li>SIMD is the most mature backend family today.</li></ul><h3 id="partial-or-mixed-maturity-paths" tabindex="-1">Partial or mixed maturity paths <a class="header-anchor" href="#partial-or-mixed-maturity-paths" aria-label="Permalink to &quot;Partial or mixed maturity paths&quot;">​</a></h3><ul><li>Metal has meaningful codegen but runtime path constraints still matter.</li><li>CUDA and ROCm have serious codegen work but runtime execution is not uniformly production-complete.</li><li>SPIR-V and WGSL generation exist, but runtime and correctness coverage are not equivalent to “all targets fully finished”.</li></ul><p>The correct reading is: SIR is a real subsystem, but backend readiness differs by target.</p><h2 id="why-this-matters-for-documentation" tabindex="-1">Why This Matters for Documentation <a class="header-anchor" href="#why-this-matters-for-documentation" aria-label="Permalink to &quot;Why This Matters for Documentation&quot;">​</a></h2><p>When documenting Vex compute, it is more accurate to say:</p><ul><li>Vex has a real SIMD/SIR pipeline</li><li>several accelerator backends exist</li><li>execution maturity varies by target and runtime path</li></ul><p>instead of implying that every backend has the same completeness and runtime guarantees.</p><h2 id="routing-and-fallbacks" tabindex="-1">Routing and Fallbacks <a class="header-anchor" href="#routing-and-fallbacks" aria-label="Permalink to &quot;Routing and Fallbacks&quot;">​</a></h2><p>The architecture includes runtime/backend selection and fallback logic. That means a graph may:</p><ul><li>stay on SIMD/CPU</li><li>route to a specific backend</li><li>fall back depending on capability, shape, or runtime constraints</li></ul><p>This is part of why backend maturity and runtime availability both matter.</p><h2 id="where-to-read-next" tabindex="-1">Where to Read Next <a class="header-anchor" href="#where-to-read-next" aria-label="Permalink to &quot;Where to Read Next&quot;">​</a></h2><ul><li><a href="/docs/guide/simd/">SIMD Overview</a></li><li><a href="/docs/guide/gpu/">GPU Programming</a></li><li><a href="/docs/guide/fusion/graph">Fusion Graph</a></li><li><a href="/docs/architecture/runtime-and-tooling">Runtime &amp; Tooling</a></li></ul>`,25)])])}const m=e(r,[["render",s]]);export{p as __pageData,m as default};
